import{C as n,o as r,c as t,a5 as a,E as l}from"./chunks/framework.CW28V7p_.js";const c=JSON.parse('{"title":"3. Shreds & erasure coding","description":"","frontmatter":{},"headers":[],"relativePath":"module-5/3-shreds.md","filePath":"module-5/3-shreds.md","lastUpdated":1780937944000}'),o={name:"module-5/3-shreds.md"},k=Object.assign(o,{setup(d){const e={id:"m5-3-shreds",title:"🧠 Mini-check: Shreds",intro:"3 питання — shred fundamentals.",questions:[{type:"mcq",q:"Чому Solana використовує shreds (1280 bytes each) замість sending full blocks?",options:["UDP packet size limit ~1500 bytes (MTU) — single packet fit best","Faster forwarding — receivers can forward shreds як тільки отримують перші, не чекати whole block","Erasure coding can recover з partial shreds","Smaller shreds менш likely до packet loss"],correct:[0,1,2,3],explanation:"Всі 4 — real reasons. UDP MTU + early forwarding + erasure resilience + loss probability. Module 5.3."},{type:"compare",q:"Data shreds vs coding shreds — у чому різниця і роль?",ideal:`Data shreds: actual TX data + block metadata. Carry useful information. Validator decoding data shreds reconstructs original block content.

Coding shreds (parity): redundancy для erasure recovery. Computed з data shreds через Reed-Solomon algorithm. Якщо deta shred lost, coding shred + remaining data shreds reconstruct missing data.

Typical ratio: 32 data + 32 coding = 64 total shreds per block batch. Можна recover з будь-якими 32 з 64 (50% loss tolerance).

За bandwidth efficiency: leader sends ВСЕ 64 (data + coding). Validator receives partial set, reconstructs. Trade-off: 2× bandwidth для recovery capability.`,explanation:"Data = useful info, coding = redundancy для loss tolerance. Module 5.3."},{type:"mcq",q:"Якщо validator отримав 25 з 64 shreds для блоку — що відбувається?",options:["Block reconstructed (25 < 32 threshold? actually <32 incomplete!)","Block НЕ reconstructed (під threshold 32)","Repair protocol запитує missing shreds","Block dropped silently"],correct:[1,2],explanation:"25 < 32 (Reed-Solomon threshold) → cannot reconstruct. Repair protocol kicks in — fetch missing shreds від peers. Якщо still не recover — slot effectively missed. Module 5.3, 5.4."}]};return(h,s)=>{const i=n("Quiz");return r(),t("div",null,[s[0]||(s[0]=a("",35)),l(i,{data:e}),s[1]||(s[1]=a("",6))])}}});export{c as __pageData,k as default};
